{
  "name": "FixNDriveAI",
  "description": "Your AI-powered automotive diagnostic assistant. Upload photos, describe symptoms, and get instant repair advice, cost estimates, and local mechanic recommendations.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ViewState {
  HOME = 'HOME',
  DIAGNOSE = 'DIAGNOSE',
  ANALYZING = 'ANALYZING',
  RESULTS = 'RESULTS',
}

export interface CarDetails {
  make: string;
  model: string;
  year: string;
  mileage: string;
  symptoms: string;
}

export interface MechanicLocation {
  name: string;
  address: string;
  rating?: number;
  openNow?: boolean;
}

export interface AnalysisResult {
  title: string;
  severity: 'Low' | 'Medium' | 'High' | 'Critical';
  summary: string;
  possibleCauses: string[];
  estimatedCost: string;
  diySteps: string[];
  recommendation: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const apiKey = process.env.API_KEY;
// Initialize GenAI client.
// Note: We create a new instance inside functions if we need to ensure fresh state,
// but for simple calls, a shared instance or creating per call is fine. 
// Given the requirements, we'll instantiate per call or globally if env is static.
const ai = new GoogleGenAI({ apiKey: apiKey });

// System instruction for the mechanic persona
const MECHANIC_SYSTEM_INSTRUCTION = `You are FixNDriveAI, an expert master mechanic with 20 years of experience. 
Your goal is to diagnose car problems based on user descriptions and images.
You should be helpful, reassuring, but realistic about safety. 
Always prioritize safety. If a vehicle is unsafe to drive, state it clearly.
Format your responses to be clean, structured, and easy for a non-mechanic to understand.`;

export const diagnoseCarIssue = async (
  details: { make: string; model: string; year: string; mileage: string; symptoms: string },
  imageBase64?: string
): Promise<AnalysisResult> => {

  const prompt = `
    Vehicle: ${details.year} ${details.make} ${details.model}
    Mileage: ${details.mileage}
    Symptoms: ${details.symptoms}

    Please analyze this issue.
    If an image is provided, use it to identify warning lights, leaks, or visible damage.

    Return the response in strictly valid JSON format matching this schema:
    {
      "title": "Short descriptive title of the issue",
      "severity": "Low" | "Medium" | "High" | "Critical",
      "summary": "2-3 sentences explaining what is likely wrong",
      "possibleCauses": ["List of 3-4 potential specific causes"],
      "estimatedCost": "Estimated repair cost range in USD (e.g. $200-$400)",
      "diySteps": ["List of 3-5 steps for a DIY fix or things to check before going to a shop"],
      "recommendation": "Final advice (e.g., Drive immediately to shop, Tow it, or Safe to drive for now)"
    }
  `;

  const parts: any[] = [{ text: prompt }];

  if (imageBase64) {
    // Determine mime type roughly or assume jpeg/png based on common web input
    // The input usually comes with prefix like "data:image/png;base64,", we need to strip it for the API usually,
    // but the @google/genai inlineData expects the raw base64 string without the prefix.
    const base64Data = imageBase64.split(',')[1];
    const mimeType = imageBase64.split(';')[0].split(':')[1];

    parts.unshift({
      inlineData: {
        data: base64Data,
        mimeType: mimeType || 'image/jpeg'
      }
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts },
      config: {
        systemInstruction: MECHANIC_SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            severity: { type: Type.STRING, enum: ['Low', 'Medium', 'High', 'Critical'] },
            summary: { type: Type.STRING },
            possibleCauses: { type: Type.ARRAY, items: { type: Type.STRING } },
            estimatedCost: { type: Type.STRING },
            diySteps: { type: Type.ARRAY, items: { type: Type.STRING } },
            recommendation: { type: Type.STRING },
          },
          required: ['title', 'severity', 'summary', 'possibleCauses', 'estimatedCost', 'diySteps', 'recommendation']
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Diagnosis error:", error);
    throw new Error("Failed to diagnose the issue. Please try again.");
  }
};

export const findNearbyMechanics = async (latitude: number, longitude: number, issueTitle: string) => {
  try {
    // We use gemini-2.5-flash for Maps Grounding
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Find highly-rated mechanics or auto repair shops near me that specialize in: ${issueTitle}. Provide a list of the top 3 options with their address and why they are good.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude,
              longitude
            }
          }
        }
      }
    });

    // We return the raw text (which will be markdown) and the grounding chunks for the UI to render maps links
    return {
      text: response.text,
      chunks: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Mechanic search error:", error);
    throw new Error("Unable to find nearby mechanics.");
  }
};

export const streamChatResponse = async function* (history: any[], newMessage: string) {
    // Using a new chat session mostly, but here we can just use generateContentStream with history if we want simplified stateless or manage state manually.
    // However, ai.chats.create is better for history.

    // Convert history to proper format
    const chatHistory = history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
    }));

    const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        history: chatHistory,
        config: {
            systemInstruction: MECHANIC_SYSTEM_INSTRUCTION,
        }
    });

    const result = await chat.sendMessageStream({ message: newMessage });

    for await (const chunk of result) {
        yield chunk.text;
    }
};

import React, { useState, useRef } from 'react';
import { CarDetails } from '../types';
import { Car, Camera, AlertTriangle, PenTool } from 'lucide-react';

interface Props {
  onSubmit: (details: CarDetails, image: string | null) => void;
  isLoading: boolean;
}

const DiagnosisForm: React.FC<Props> = ({ onSubmit, isLoading }) => {
  const [details, setDetails] = useState<CarDetails>({
    make: '',
    model: '',
    year: '',
    mileage: '',
    symptoms: ''
  });
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setDetails(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(details, imagePreview);
  };

  return (
    <div className="w-full max-w-2xl mx-auto bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100">
      <div className="bg-slate-900 p-6 text-white flex items-center gap-3">
        <Car className="w-6 h-6 text-orange-500" />
        <h2 className="text-xl font-bold">New Diagnosis</h2>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-6">

        {/* Vehicle Info Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Year</label>
            <input
              required
              type="number"
              name="year"
              placeholder="e.g. 2018"
              className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-orange-500 focus:border-orange-500 outline-none transition"
              value={details.year}
              onChange={handleChange}
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Make</label>
            <input
              required
              type="text"
              name="make"
              placeholder="e.g. Toyota"
              className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-orange-500 focus:border-orange-500 outline-none transition"
              value={details.make}
              onChange={handleChange}
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Model</label>
            <input
              required
              type="text"
              name="model"
              placeholder="e.g. Camry"
              className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-orange-500 focus:border-orange-500 outline-none transition"
              value={details.model}
              onChange={handleChange}
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Mileage (approx)</label>
            <input
              required
              type="text"
              name="mileage"
              placeholder="e.g. 85,000"
              className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-orange-500 focus:border-orange-500 outline-none transition"
              value={details.mileage}
              onChange={handleChange}
            />
          </div>
        </div>

        {/* Symptoms */}
        <div className="space-y-2">
          <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
            <PenTool className="w-4 h-4" />
            Description of the Problem
          </label>
          <textarea
            required
            name="symptoms"
            rows={4}
            placeholder="Describe what's happening... e.g., 'Strange grinding noise when braking', 'Check engine light is on', 'Steam coming from hood'"
            className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-orange-500 focus:border-orange-500 outline-none transition resize-none"
            value={details.symptoms}
            onChange={handleChange}
          />
        </div>

        {/* Image Upload */}
        <div className="space-y-2">
          <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
            <Camera className="w-4 h-4" />
            Upload Photo (Optional)
          </label>
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="border-2 border-dashed border-slate-300 rounded-lg p-6 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition group"
          >
            {imagePreview ? (
              <div className="relative w-full h-48">
                <img src={imagePreview} alt="Preview" className="w-full h-full object-contain rounded-md" />
                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition text-white font-medium">
                  Change Photo
                </div>
              </div>
            ) : (
              <>
                <div className="bg-slate-100 p-3 rounded-full mb-3 group-hover:bg-slate-200 transition">
                  <Camera className="w-6 h-6 text-slate-500" />
                </div>
                <p className="text-slate-500 text-sm">Click to upload a photo of the dashboard or issue</p>
              </>
            )}
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*"
              onChange={handleImageUpload}
            />
          </div>
        </div>

        {/* Submit */}
        <button
          type="submit"
          disabled={isLoading}
          className={`w-full py-4 rounded-lg text-white font-bold text-lg flex items-center justify-center gap-2 shadow-lg transition
            ${isLoading ? 'bg-slate-400 cursor-not-allowed' : 'bg-orange-600 hover:bg-orange-700 hover:shadow-orange-500/30'}
          `}
        >
          {isLoading ? (
            <>
              <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Diagnosing...
            </>
          ) : (
            <>
              <AlertTriangle className="w-5 h-5" />
              Analyze Problem
            </>
          )}
        </button>

      </form>
    </div>
  );
};

export default DiagnosisForm;

import React, { useState, useEffect, useRef } from 'react';
import { AnalysisResult, ChatMessage } from '../types';
import { findNearbyMechanics, streamChatResponse } from '../services/geminiService';
import ReactMarkdown from 'react-markdown'; // Actually we don't have this library in list, so we'll do simple rendering or just text.
// Wait, prompt says "Use popular and existing libraries". I will avoid extra deps if possible to keep it simple, or use simple pre/whitespace.
// Let's use simple whitespace rendering for chat.

import { 
  Wrench, 
  MapPin, 
  DollarSign, 
  AlertOctagon, 
  CheckCircle, 
  MessageSquare,
  ArrowRight,
  Send,
  Loader2,
  ChevronRight
} from 'lucide-react';

interface Props {
  result: AnalysisResult;
  onReset: () => void;
  carName: string; // "2018 Toyota Camry"
}

const ResultsView: React.FC<Props> = ({ result, onReset, carName }) => {
  const [activeTab, setActiveTab] = useState<'details' | 'mechanic' | 'chat'>('details');
  const [mechanics, setMechanics] = useState<{text: string, chunks: any[] | undefined} | null>(null);
  const [findingMechanics, setFindingMechanics] = useState(false);

  // Chat state
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [inputMsg, setInputMsg] = useState('');
  const [isChatting, setIsChatting] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Severity color mapping
  const getSeverityColor = (sev: string) => {
    switch (sev) {
      case 'Critical': return 'bg-red-600 text-white';
      case 'High': return 'bg-orange-500 text-white';
      case 'Medium': return 'bg-yellow-500 text-white';
      default: return 'bg-green-500 text-white';
    }
  };

  const handleFindMechanics = async () => {
    setActiveTab('mechanic');
    if (mechanics) return; // already loaded

    setFindingMechanics(true);
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser");
      setFindingMechanics(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(async (position) => {
      try {
        const data = await findNearbyMechanics(
          position.coords.latitude, 
          position.coords.longitude, 
          result.title
        );
        setMechanics(data);
      } catch (e) {
        console.error(e);
      } finally {
        setFindingMechanics(false);
      }
    }, () => {
      alert("Unable to retrieve your location");
      setFindingMechanics(false);
    });
  };

  const handleSendChat = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputMsg.trim() || isChatting) return;

    const newMsg: ChatMessage = { role: 'user', text: inputMsg, timestamp: Date.now() };
    setChatHistory(prev => [...prev, newMsg]);
    setInputMsg('');
    setIsChatting(true);

    try {
      // Build context from analysis result if it's the first message
      let historyToSend = [...chatHistory];
      if (chatHistory.length === 0) {
        // Seed with context
        historyToSend = [
          { role: 'user', text: `I have a ${carName}. Issue: ${result.title}. Diagnosis: ${result.summary}.` },
          { role: 'model', text: "Understood. I am ready to help you further with this issue.", timestamp: Date.now() }
        ];
      }

      const stream = streamChatResponse(historyToSend, newMsg.text);
      let fullResponse = "";

      // Add placeholder for model response
      setChatHistory(prev => [...prev, { role: 'model', text: "", timestamp: Date.now() }]);

      for await (const chunk of stream) {
        fullResponse += chunk;
        setChatHistory(prev => {
          const updated = [...prev];
          updated[updated.length - 1].text = fullResponse;
          return updated;
        });
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsChatting(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'chat') {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatHistory, activeTab]);

  return (
    <div className="w-full max-w-4xl mx-auto space-y-6">

      {/* Header Card */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="bg-slate-900 p-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h2 className="text-2xl font-bold text-white">{result.title}</h2>
            <p className="text-slate-400">{carName}</p>
          </div>
          <div className={`px-4 py-2 rounded-full font-bold uppercase text-sm tracking-wide ${getSeverityColor(result.severity)}`}>
            {result.severity} Severity
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="flex border-b border-slate-200">
          <button 
            onClick={() => setActiveTab('details')}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'details' ? 'text-orange-600 border-b-2 border-orange-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Analysis Details
          </button>
          <button 
            onClick={handleFindMechanics}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'mechanic' ? 'text-orange-600 border-b-2 border-orange-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Find Mechanic
          </button>
          <button 
            onClick={() => setActiveTab('chat')}
            className={`flex-1 py-4 text-center font-medium transition ${activeTab === 'chat' ? 'text-orange-600 border-b-2 border-orange-600' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Ask AI Mechanic
          </button>
        </div>

        <div className="p-6 md:p-8 min-h-[400px]">

          {/* TAB: DETAILS */}
          {activeTab === 'details' && (
            <div className="space-y-8 animate-fadeIn">

              <div className="prose prose-slate max-w-none">
                <h3 className="text-lg font-semibold text-slate-800 mb-2">Summary</h3>
                <p className="text-slate-600 leading-relaxed">{result.summary}</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-slate-50 p-5 rounded-xl border border-slate-100">
                  <h4 className="font-semibold text-slate-800 mb-3 flex items-center gap-2">
                    <AlertOctagon className="w-5 h-5 text-orange-500" />
                    Possible Causes
                  </h4>
                  <ul className="space-y-2">
                    {result.possibleCauses.map((cause, i) => (
                      <li key={i} className="flex items-start gap-2 text-slate-600 text-sm">
                        <span className="w-1.5 h-1.5 bg-orange-400 rounded-full mt-2 flex-shrink-0" />
                        {cause}
                      </li>
                    ))}
                  </ul>
                </div>

                <div className="bg-slate-50 p-5 rounded-xl border border-slate-100">
                  <h4 className="font-semibold text-slate-800 mb-3 flex items-center gap-2">
                    <DollarSign className="w-5 h-5 text-green-600" />
                    Estimated Cost
                  </h4>
                  <p className="text-2xl font-bold text-slate-700">{result.estimatedCost}</p>
                  <p className="text-xs text-slate-500 mt-1">Estimates include parts & labor. Varies by location.</p>
                </div>
              </div>

              <div>
                <h4 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
                  <Wrench className="w-5 h-5 text-blue-500" />
                  Recommended Action: {result.recommendation}
                </h4>
                <div className="space-y-3">
                  {result.diySteps.map((step, i) => (
                     <div key={i} className="flex gap-4">
                       <div className="flex-shrink-0 w-8 h-8 rounded-full bg-slate-200 text-slate-600 flex items-center justify-center font-bold text-sm">
                         {i + 1}
                       </div>
                       <p className="text-slate-600 pt-1">{step}</p>
                     </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {/* TAB: MECHANIC */}
          {activeTab === 'mechanic' && (
            <div className="space-y-6 animate-fadeIn">
              {findingMechanics ? (
                <div className="flex flex-col items-center justify-center py-12 text-slate-500">
                  <Loader2 className="w-10 h-10 animate-spin text-orange-500 mb-4" />
                  <p>Searching for specialists nearby...</p>
                </div>
              ) : mechanics ? (
                <div>
                   <h3 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
                     <MapPin className="w-5 h-5 text-red-500" />
                     Top Recommendations Near You
                   </h3>
                   <div className="prose prose-sm max-w-none text-slate-600 bg-slate-50 p-6 rounded-xl border border-slate-200">
                     {/* Rendering text with line breaks */}
                     {mechanics.text.split('\n').map((line, i) => (
                       <p key={i} className="mb-2">{line}</p>
                     ))}
                   </div>
                   {/* Maps Grounding Links */}
                   {mechanics.chunks && mechanics.chunks.length > 0 && (
                     <div className="mt-6 space-y-3">
                       <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Source Links</h4>
                        {mechanics.chunks.map((chunk, idx) => (
                          chunk.googleMapsMetadata?.place?.name && (
                            <a 
                              key={idx}
                              href={chunk.googleMapsMetadata.place.googleMapsUri}
                              target="_blank"
                              rel="noreferrer"
                              className="block p-4 bg-white border border-slate-200 rounded-lg hover:border-blue-400 hover:shadow-md transition flex items-center justify-between group"
                            >
                              <div>
                                <div className="font-medium text-slate-800 group-hover:text-blue-600">{chunk.googleMapsMetadata.place.name}</div>
                                <div className="text-xs text-slate-500">{chunk.googleMapsMetadata.place.formattedAddress}</div>
                              </div>
                              <ChevronRight className="w-5 h-5 text-slate-300 group-hover:text-blue-500" />
                            </a>
                          )
                        ))}
                     </div>
                   )}
                </div>
              ) : (
                <div className="text-center py-12 text-slate-500">
                  <p>Click "Find Mechanic" to locate help.</p>
                </div>
              )}
            </div>
          )}

          {/* TAB: CHAT */}
          {activeTab === 'chat' && (
            <div className="flex flex-col h-[500px] animate-fadeIn">
              <div className="flex-1 overflow-y-auto space-y-4 pr-2 mb-4">
                {chatHistory.length === 0 && (
                   <div className="text-center text-slate-400 py-10">
                     <MessageSquare className="w-12 h-12 mx-auto mb-3 opacity-20" />
                     <p>Ask follow-up questions about the repair, costs, or parts.</p>
                   </div>
                )}
                {chatHistory.map((msg, idx) => (
                  <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] rounded-2xl p-4 text-sm leading-relaxed
                      ${msg.role === 'user' 
                        ? 'bg-blue-600 text-white rounded-br-none' 
                        : 'bg-slate-100 text-slate-800 rounded-bl-none'}
                    `}>
                      {msg.text}
                    </div>
                  </div>
                ))}
                <div ref={chatEndRef} />
              </div>
              <form onSubmit={handleSendChat} className="flex gap-2 border-t border-slate-200 pt-4">
                <input
                  type="text"
                  value={inputMsg}
                  onChange={(e) => setInputMsg(e.target.value)}
                  placeholder="Ask a question..."
                  className="flex-1 px-4 py-3 rounded-xl border border-slate-300 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                />
                <button 
                  type="submit"
                  disabled={!inputMsg.trim() || isChatting}
                  className="bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white p-3 rounded-xl transition"
                >
                  {isChatting ? <Loader2 className="w-6 h-6 animate-spin" /> : <Send className="w-6 h-6" />}
                </button>
              </form>
            </div>
          )}

        </div>
      </div>

      <div className="text-center">
        <button 
          onClick={onReset}
          className="text-slate-500 hover:text-slate-800 font-medium text-sm flex items-center justify-center gap-2 mx-auto transition"
        >
          <ArrowRight className="w-4 h-4 rotate-180" /> Start New Diagnosis
        </button>
      </div>
    </div>
  );
};

